@using sv_ecca7195499b44e6951e39e46c4d25b6.Models

<div class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted mb-0">Settings</h5>
    <nav class="nav flex-column">
        @foreach (var section in _sections)
        {
            <button class="nav-link sidebar-link @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => OnSectionSelected.InvokeAsync(section.Key)">
                <span class="sidebar-icon">@section.Value.Icon</span>
                @section.Value.Label
            </button>
        }
    </nav>
</div>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["Profile"] = ("Profile", "👤"),
        ["Notifications"] = ("Notifications", "🔔"),
        ["Security"] = ("Security", "🔒"),
        ["Appearance"] = ("Appearance", "🎨")
    };
}

.settings-sidebar {
    background-color: #f8f9fa;
    border-right: 1px solid #dee2e6;
    min-height: 100%;
    padding-top: 0.5rem;
}

.sidebar-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.65rem 1rem;
    color: #495057;
    border: none;
    background: none;
    text-align: left;
    width: 100%;
    font-size: 0.95rem;
    border-left: 3px solid transparent;
    transition: background-color 0.15s, border-color 0.15s;
}

.sidebar-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

.sidebar-link.active {
    background-color: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

@using sv_ecca7195499b44e6951e39e46c4d25b6.Models
@inject ISettingsService SettingsService

<div class="profile-section">
    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else
    {
        <h4 class="mb-4">Profile</h4>

        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>

            <div class="col-md-4 text-center">
                <label class="form-label fw-semibold d-block">Avatar Preview</label>
                <div class="avatar-preview mb-2">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" width="120" height="120" />
                    }
                    else
                    {
                        <div class="avatar-placeholder rounded-circle">👤</div>
                    }
                </div>
                <div class="mb-3">
                    <label class="form-label text-muted small">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" />
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@(!_hasChanges)">
                Discard Changes
            </button>
        </div>
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    // Snapshot of last-saved state for discard
    private UserProfile? _savedProfile;

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private bool _hasChanges =>
        _savedProfile is not null &&
        (_displayName != _savedProfile.DisplayName ||
         _email != _savedProfile.Email ||
         _bio != _savedProfile.Bio ||
         _avatarUrl != _savedProfile.AvatarUrl);

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _savedProfile = p;
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _statusMessage = "Profile saved successfully.";
            _isError = false;
        }
        catch
        {
            _statusMessage = "Failed to save profile. Please try again.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
            _statusMessage = null;
        }
    }
}

.avatar-preview {
    display: flex;
    justify-content: center;
    align-items: center;
}

.avatar-placeholder {
    width: 120px;
    height: 120px;
    background-color: #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 3rem;
}

@using sv_ecca7195499b44e6951e39e46c4d25b6.Models
@using sv_ecca7195499b44e6951e39e46c4d25b6.Services
@inject ISettingsService SettingsService

<div class="notifications-section">
    @if (_loading)
    {
        <p class="text-muted">Loading notification preferences…</p>
    }
    else
    {
        <h4 class="mb-4">Notifications</h4>

        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Notification Channels</h6>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailToggle"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="emailToggle">
                        Email Notifications
                        <small class="text-muted d-block">Receive notifications via email</small>
                    </label>
                </div>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushToggle"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="pushToggle">
                        Push Notifications
                        <small class="text-muted d-block">Receive browser push notifications</small>
                    </label>
                </div>

                <div class="form-check form-switch mb-2">
                    <input class="form-check-input" type="checkbox" id="digestToggle"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="digestToggle">
                        Weekly Digest
                        <small class="text-muted d-block">Get a summary email once a week</small>
                    </label>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Muted Channels</h6>
                <p class="text-muted small">Check channels you want to mute.</p>

                @foreach (var channel in _allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label text-capitalize" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Preferences
        </button>
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _allChannels = new();

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);

        // Get full channel list from the mock service
        if (SettingsService is MockSettingsService mock)
        {
            _allChannels = mock.GetAllChannels();
        }
        else
        {
            _allChannels = prefs.MutedChannels;
        }

        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        var prefs = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _statusMessage = "Notification preferences saved.";
        _saving = false;
    }
}

@using sv_ecca7195499b44e6951e39e46c4d25b6.Models

<!-- Confirmation Modal -->
@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong>
                        from <strong>@_sessionToRevoke.Location</strong>?</p>
                    <p class="text-muted small mb-0">This will sign that device out immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @if (_revoking) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Revoke
                    </button>
                </div>
            </div>
        </div>
    </div>
}

<div class="table-responsive">
    <table class="table table-hover align-middle mb-0">
        <thead class="table-light">
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th class="text-end">Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>
                        @session.Device
                        @if (session.Id == CurrentSessionId)
                        {
