@code {
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    // Snapshot of last-saved state for discard
    private UserProfile? _savedProfile;

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private bool _hasChanges =>
        _savedProfile is not null &&
        (_displayName != _savedProfile.DisplayName ||
         _email != _savedProfile.Email ||
         _bio != _savedProfile.Bio ||
         _avatarUrl != _savedProfile.AvatarUrl);

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _savedProfile = p;
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _statusMessage = "Profile saved successfully.";
            _isError = false;
        }
        catch
        {
            _statusMessage = "Failed to save profile. Please try again.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
            _statusMessage = null;
        }
    }
}
