                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword"
                           @bind:after="ValidateConfirm" />
                    @if (_confirmMismatch)
                    {
                        <div class="text-danger small mt-1">Passwords do not match.</div>
                    }
                </div>
                <button class="btn btn-warning" @onclick="Submit" disabled="@(!CanSubmit)">
