@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _confirmMismatch;
    private bool _submitting;
    private string? _message;
    private bool _isError;

    private bool CanSubmit =>
        !_submitting &&
        !string.IsNullOrWhiteSpace(_currentPassword) &&
        !string.IsNullOrWhiteSpace(_newPassword) &&
        _newPassword == _confirmPassword;

    private void ValidateConfirm()
    {
        _confirmMismatch = !string.IsNullOrEmpty(_confirmPassword) && _newPassword != _confirmPassword;
    }

    private async Task Submit()
    {
        _submitting = true;
        _message = null;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _message = "Password updated successfully.";
            _isError = false;
            _currentPassword = _newPassword = _confirmPassword = "";
        }
        catch
        {
            _message = "Failed to change password.";
            _isError = true;
        }
        finally
        {
            _submitting = false;
        }
    }
}
