            <div class="col-lg-6">
                <h6 class="mb-3">Preview</h6>
                <div class="preview-area @PreviewThemeClass" style="@PreviewStyle">
                    <div class="preview-card @(_compactMode ? "compact" : "")">
                        <div class="preview-header">Dashboard</div>
