toolArgs.file_text:
@using sv_ecca7195499b44e6951e39e46c4d25b6.Models
@inject ISettingsService SettingsService

<div class="appearance-section">
    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <h4 class="mb-4">Appearance</h4>

        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-lg-6">
                <!-- Theme -->
                <div class="card mb-3">
                    <div class="card-body">
                        <h6 class="card-title">Theme</h6>
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <!-- Font Size -->
                <div class="card mb-3">
                    <div class="card-body">
                        <h6 class="card-title">Font Size</h6>
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <!-- Language -->
                <div class="card mb-3">
                    <div class="card-body">
                        <h6 class="card-title">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>
                </div>

                <!-- Compact Mode -->
                <div class="card mb-3">
                    <div class="card-body d-flex justify-content-between align-items-center">
                        <div>
                            <h6 class="mb-1">Compact Mode</h6>
                            <small class="text-muted">Reduce spacing and padding throughout the UI</small>
                        </div>
                        <div class="form-check form-switch mb-0">
                            <input class="form-check-input" type="checkbox" id="compactToggle"
                                   checked="@_compactMode"
                                   @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        </div>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save
                </button>
            </div>

            <!-- Live Preview -->
            <div class="col-lg-6">
                <h6 class="mb-3">Preview</h6>
                <div class="preview-area @PreviewThemeClass" style="@PreviewStyle">
                    <div class="preview-card @(_compactMode ? "compact" : "")">
                        <div class="preview-header">Dashboard</div>
                        <div class="preview-body">
                            <p class="preview-text">This is how your content will look with the selected settings.</p>
                            <div class="preview-stats">
                                <span class="preview-stat">📊 Analytics</span>
                                <span class="preview-stat">📁 Projects</span>
                                <span class="preview-stat">👥 Team</span>
                            </div>
                            <div class="preview-meta">
                                Theme: @_theme · Font: @_fontSize · Lang: @_language
                                @if (_compactMode) { <span>· Compact</span> }
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string PreviewStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _statusMessage = "Appearance settings saved.";
        _saving = false;
    }
}

.preview-area {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.25rem;
